(function() {
    /*======== 版本更新日志 ========*/
    /*
     * 作者：sjshb57
     * GitHub：https://github.com/sjshb57/legado-57
     *
     * [v2.8.3] 第三十二次修改 - 优化代码
     * - 优化步骤0逻辑，改用黑名单而非白名单：含有限定字符（票更快祝新迎章订架求免）的括号内容随整体删除，降低误删概率，其余转为半角格式
     * - 
     */

    // ========= 1. 功能文档 =========
    /*
     * 功能概述：
     * 本脚本是一个高级中文数字标题转换工具，专门用于处理各种格式的中文数字标题，
     * 将其转换为统一的阿拉伯数字格式，同时提供多种智能处理选项。
     *
     * 主要功能：
     * 1. 全面支持简繁体中文数字转换（零-萬）
     * 2. 智能空格处理（自动补全章节号与内容间的空格）
     * 3. 标点符号统一清理（入口处集中处理，覆盖所有标题类型）
     * 4. 特殊章节处理（『第零章』→『序章』）
     * 5. 支持纯数字标题转换（『1 内容』→『第1章 内容』）
     * 6. 无标识符标题兼容（『第一百标题』→『第100章 标题』）
     * 7. 多章节标识符适配（章/节/回/集等）
     * 8. 灵活的配置系统（可自定义删除的标点字符集、默认章节后缀等）
     * 9. 标识符白名单保护（指定标识符不被 defaultSuffix 覆盖）
     * 10. 括号内容清理（非黑名单字符保留并转为半角格式，其余内容随整体删除）
     *
     * 典型输入输出示例：
     * 输入 → 输出
     * ----------------------------------------
     * 基础数字转换
     * 『第一章 内容』  → 『第1章 内容』
     * 『第壹佰贰拾叁节』→ 『第123节』
     * 『第伍萬陆仟柒佰捌拾篇』→ 『第56780篇』
     *
     * 零值与特殊格式
     * 『第零回 内容』 → 『序回 内容』（convertZeroToPreface=true时）
     * 『第〇章 空白』 → 『第0章 空白』（convertZeroToPreface=false时）
     * 『第一章标题』 → 『第1篇 标题』（defaultSuffix='篇'时替换，无标识符时进行补全）
     *
     * 空格与标点规范
     * 『第1章内容』   → 『第1章 内容』（自动补空格）
     * 『第1章：简介』 → 『第1章：简介』（中文标点前不补空格）
     * 『请，假。』    → 『请假』（移除非章节标题中的指定标点）
     *
     * 纯数字标题处理
     * 『123』        → 『第123章』
     * 『456内容』    → 『第456章 内容』
     * 『01 测试』    → 『第01章 测试』
     *
     * 混合与边界示例
     * 『第1章　内容』 → 『第1章　内容』（保留全角空格）
     * 『第零章测试』  → 『序章 测试』（零值转换+自动补空格）
     * 『第100章.』   → 『第100章』（末尾标点清理）
     *
     * 括号内容处理
     * 『第1章（上）内容』      → 『第1章 (上) 内容』（非黑名单，转为半角格式）
     * 『第1章内容（已更新）』  → 『第1章内容』（命中黑名单字符'章'/'更'，整体删除）
     * 『第2章（上』           → 『第2章 (上)』（未闭合且非黑名单，补右括号转半角）
     */

    // ========= 2. 配置系统 =========
    /*
     * 可通过 Config 对象调整以下配置项：
     *
     * punctuationsToRemove {string} 默认 '.。,，'
     *   需要统一删除的标点字符集（作为正则字符类使用）。
     *   在 processTitle 入口处统一预处理，覆盖所有标题类型：
     *   示例：'.。,，' → 删除英文句点、中文句号、英文逗号、中文逗号
     *
     * convertZeroToPreface {boolean} 默认 false
     *   是否将第零章/第零回等转换为序章/序回
     *   示例：『第零回』→『序回』（true时）
     *
     * defaultSuffix {string} 默认 '章'
     *   统一使用的章节后缀，无论原标题是否含标识符均生效使用
     *   示例：『第一百标题』→『第100章 标题』
     *   设置为『篇』时：→『第100篇 标题』
     *
     * preserveSuffixes {string} 默认 '卷'
     *   标识符白名单，字符串中每个字符均视为一个受保护的标识符。
     *   白名单内的标识符原样保留，不被 defaultSuffix 覆盖。
     *   示例：'卷' → 『第二卷』保留为『第2卷』，其他标识符仍用 defaultSuffix
     *   设为空字符串时，所有标识符均跟随 defaultSuffix 替换。
     */
    const Config = {
        punctuationsToRemove: '.。,，', // 需要统一删除的标点字符集
        convertZeroToPreface: false, // 是否将零值转换为"序"
        defaultSuffix: '章', // 覆盖使用此章节标识后缀
        preserveSuffixes: '卷' // 白名单：这些标识符不被 defaultSuffix 覆盖，原样保留（空字符串则全部替换）
    };

    // ====== 3. 正则表达式系统 ======
    /*
     * Regex 对象封装所有预编译的正则表达式，避免重复编译，提升性能。
     * 其中标点相关的三条正则均根据 Config.punctuationsToRemove 动态构建。
     *
     * patterns 中各正则说明：
     *
     * chinesePunctuation  /^[：、，；？！（）「」【】]/
     *   检测内容是否以中文标点开头，用于阻止在标点前自动插入空格。
     *   示例：『：内容』→ 匹配，不补空格
     *
     * chapter  /^第(\d+|[中文数字]+)([章节回集卷部篇话讲段]?)(.*)/
     *   主匹配正则，提取章节标题的三个部分：
     *     第1组：章节数字，优先匹配阿拉伯数字，其次匹配中文数字（支持简繁体及财务大写）
     *     第2组：章节标识符（可选，如章/节/回/集等）
     *     第3组：标题内容
     *   示例：
     *     『第1章 内容』        → ['1', '章', ' 内容']
     *     『第壹佰贰拾叁节 内容』→ ['壹佰贰拾叁', '节', ' 内容']
     *     『第一百标题』        → ['一百', '', '标题']
     *
     * digitalChapter  /^(\d+)\s*(.*)/
     *   匹配纯数字开头的标题：
     *     第1组：数字部分
     *     第2组：剩余内容（含数字后可能残留的空白与标点）
     *   示例：
     *     『123 内容』→ ['123', '内容']
     *     『456测试』 → ['456', '测试']
     *
     * titlePunctuation  （动态生成）
     *   匹配标题末尾连续的指定标点，用于「第」开头标题的末尾清理。
     *
     * allPunctuations  （动态生成）
     *   匹配全文中所有指定标点（global flag），用于非章节标题的全文清理。
     *
     * leadingPunctuations  （动态生成）
     *   匹配字符串开头连续的空白及指定标点，用于清理内容前导杂符。
     */
    const escaped = Config.punctuationsToRemove.replace(/[-\]\\^]/g, '\\$&');
    const Regex = {
        patterns: {
            chinesePunctuation: /^[：、，；？！（）「」【】]/,
            chapter: /^第(\d+|[零〇一二三四五六七八九十百千两万壹贰叁肆伍陆柒捌玖拾佰仟萬貳參陸]+)([章节回集卷部篇话讲段]?)(.*)/,
            digitalChapter: /^(\d+)\s*(.*)/,
            titlePunctuation: new RegExp('[' + escaped + ']+$'),
            allPunctuations: new RegExp('[' + escaped + ']', 'g'),
            leadingPunctuations: new RegExp('^[\\s' + escaped + ']+')
        }
    };

    // ======= 4. 数字转换系统 =======
    /*
     * NumberConverter 负责将中文数字字符串转换为阿拉伯数字。
     *
     * map 映射表覆盖：
     *   基础数字：零〇一二两三四五六七八九（含同义词）
     *   单位数字：十百千万（进位单位）
     *   财务大写：壹贰叁肆伍陆柒捌玖拾佰仟萬
     *   繁体数字：貳參陸
     *
     * convert 算法（逐字扫描，O(n) 时间，O(1) 空间）：
     *   维护两个变量：
     *     total - 已完成计算的累计值
     *     temp  - 当前待与进位单位相乘的临时值
     *
     *   规则：
     *   - 遇到进位单位（十/百/千/万）：
     *       temp 若为0（如『十二』的『十』前无数字），按1处理
     *       temp × 单位 → 累加到 total，temp 归零
     *   - 遇到普通数字字符：temp += 数值
     *   - 循环结束后：total + temp 即为最终结果
     *
     *   示例：『貳佰叁拾』
     *     貳(2)→temp=2
     *     佰(100)→temp=2×100=200→total=200，temp=0
     *     叁(3)→temp=3
     *     拾(10)→temp=3×10=30→total=230，temp=0
     *     结果：230
     *
     *   示例：『壹萬伍仟陆佰柒拾捌』
     *     壹→temp=1；萬→total=10000，temp=0
     *     伍→temp=5；仟→total=15000，temp=0
     *     陆→temp=6；佰→total=15600，temp=0
     *     柒→temp=7；拾→total=15670，temp=0
     *     捌→temp=8
     *     结果：15678
     */
    const NumberConverter = {
        map: {
            // 基础数字
            '零': 0,
            '〇': 0,
            '一': 1,
            '二': 2,
            '两': 2,
            '三': 3,
            '四': 4,
            '五': 5,
            '六': 6,
            '七': 7,
            '八': 8,
            '九': 9,
            // 进位单位
            '十': 10,
            '百': 100,
            '千': 1000,
            '万': 10000,
            // 财务大写
            '壹': 1,
            '贰': 2,
            '叁': 3,
            '肆': 4,
            '伍': 5,
            '陆': 6,
            '柒': 7,
            '捌': 8,
            '玖': 9,
            '拾': 10,
            '佰': 100,
            '仟': 1000,
            '萬': 10000,
            // 繁体
            '貳': 2,
            '參': 3,
            '陸': 6
        },

        convert: function(chineseNum) {
            let total = 0;
            let temp = 0;

            for (let i = 0; i < chineseNum.length; i++) {
                const val = this.map[chineseNum[i]];
                if ([10, 100, 1000, 10000].includes(val)) {
                    // 遇到进位单位：temp 为 0 时视为隐含的 1（如『十二』→12）
                    temp = (temp === 0 ? 1 : temp) * val;
                    total += temp;
                    temp = 0;
                } else if (val !== undefined) {
                    temp += val;
                }
            }

            return total + temp;
        }
    };

    // ======== 5. 主处理函数 ========

    function processTitle(title) {

        // --- 步骤0：括号内容处理 ---
        // 黑名单字符集：含有以下这些字符的括号内容进行整体删除。
        // 匹配所有中英文括号对：
        //   - 内容命中黑名单字符时，整体删除
        //   - 其他内容替换为「 (内容)」（半角括号，前置空格），未闭合括号自动补右括号
        const bracketBlacklist = /[票更快祝新迎章订架求免]/;
        title = title.replace(/[（(]([^）)]*)[）)]|[（(]([^）)]*)$/g, (_, closed, open) => {
            const inner = closed ?? open;
            return bracketBlacklist.test(inner) ? '' : ' (' + inner + ')';
        });
        // --- 步骤1：统一标点预处理 ---
        // 根据标题类型，对 punctuationsToRemove 中的标点执行不同范围的清理：
        //   - 以「第」开头（中文章节标题）：仅清理末尾连续标点（保留正文内容）
        //   - 以数字开头（纯数字标题）    ：步骤2匹配后对 content 部分单独清理
        //   - 其他标题                    ：清理全文所有指定标点
        if (title.startsWith('第')) {
            title = title.replace(Regex.patterns.titlePunctuation, '');
        } else if (!Regex.patterns.digitalChapter.test(title)) {
            title = title.replace(Regex.patterns.allPunctuations, '');
        }

        // --- 步骤2：纯数字标题处理 ---
        // 匹配以数字开头的标题，清理数字后的前导标点，统一转换为「第N章 内容」格式。
        const digitalMatch = title.match(Regex.patterns.digitalChapter);
        if (digitalMatch) {
            const [, num, content] = digitalMatch;
            const cleanedContent = content.replace(Regex.patterns.leadingPunctuations, '').trim();
            return cleanedContent ?
                `第${num}${Config.defaultSuffix} ${cleanedContent}` :
                `第${num}${Config.defaultSuffix}`;
        }

        // --- 步骤3：非「第」开头标题处理 ---
        // 不以「第」开头则无章节号可转换，直接返回。
        if (!title.startsWith('第')) {
            return title;
        }

        // --- 步骤4：正则匹配标题各部分 ---
        // 提取章节标题的三个组成部分：
        //   chineseNum     - 中文或阿拉伯数字字符串（如「壹佰贰拾叁」）
        //   originalSuffix - 章节标识符（如「节」，可能为空字符串）
        //   titlePart      - 标题内容（如「 内容」，含原始前导空白与标点）
        // 若匹配失败（如「第abc章」），原样返回。
        const match = title.match(Regex.patterns.chapter);
        if (!match) return title;

        const [, chineseNum, originalSuffix, titlePart] = match;

        // 无标识符时，若 titlePart 为以下标识符开头，则原样返回（避免误匹配）
        if (!originalSuffix && /^[季年月日周天期次]/.test((titlePart || '').trimStart())) {
            return title;
        }

        // suffix：白名单内的标识符原样保留，其余统一使用 defaultSuffix。
        let suffix = (originalSuffix && Config.preserveSuffixes.includes(originalSuffix)) ?
            originalSuffix :
            Config.defaultSuffix;

        // 清理章节标识符后的前导空白与标点（如「，内容」→「内容」）
        const cleanTitlePart = (titlePart || '').replace(Regex.patterns.leadingPunctuations, '').trim();

        // --- 步骤5：数字转换 ---
        // chineseNum 为阿拉伯数字时直接使用，否则调用 NumberConverter.convert 转换。
        let number = /^\d+$/.test(chineseNum) ? chineseNum : NumberConverter.convert(chineseNum);

        // --- 步骤6：零值特殊处理 ---
        // convertZeroToPreface=true 且转换结果为 0 时，
        // 将「第零章」形式转换为「序章」：number 清空，suffix 前缀加「序」。
        if (number === 0 && Config.convertZeroToPreface) {
            number = '';
            suffix = '序' + suffix;
        }

        // --- 步骤7：空格处理与结果组装 ---
        // 始终自动补空格，但中文标点开头的内容除外（如「：内容」不需补空格）。
        if (cleanTitlePart) {
            const shouldAddSpace = !Regex.patterns.chinesePunctuation.test(cleanTitlePart);
            return `第${number}${suffix}${shouldAddSpace ? ' ' : ''}${cleanTitlePart}`;
        }

        // 无标题时直接返回「第N章」格式
        return `第${number}${suffix}`;
    }

    // ========== 执行入口 ==========
    // result 是阅读软件传入的原始标题文本，processTitle 处理后返回转换结果。
    // 整体执行时间受 timeoutMillisecond（3000ms）限制。
    return processTitle(result);
})();
